#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1 = (vUv-.5) * uAspect.xy;


float rota = lum(texture(sampler_noise_hq,q30*vUv+.001*uTime))*3.14;


uv6 = multiply(uv1,mat2(cos(rota),-sin(rota),sin(rota),cos(rota)));


mus = .2/(sqrt(uv6.y)+.2);
mus = abs(mus);
mus *= vec3 (1,.96,.9);

vec3 no = texture(sampler_noise_lq,vUv)-.5;
mus *= vec3 (1,.96,.9) + 0.1*no;

color =  1;

vec3 blur = GetBlur1(fract(vUv));

vec2 hor = vec2 (0.004,0);
vec2 ver = vec2 (0,.004);

dx = lum(texture(sampler_main,vUv+hor)
         - texture(sampler_main,vUv-hor));
dy = lum(texture(sampler_main,vUv+ver)
         - texture(sampler_main,vUv-ver));

vec2 zz = vec2 (dx,dy);

vec3 crisp= texture(sampler_main,vUv+zz*.02);
vec3 crisp2 = .5*texture(sampler_main,vUv);
crisp += crisp2;
crisp *= .667;
crisp +=.018*color - length(zz)*blur;

vec3 ret1 = crisp - blur*.03 + .04*mus;
//ret1 -= abs(mus)/52;
ret = ret1 * .99 -  .04 ;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

screen3 = vec3 ((vUv-.5)*uAspect.xy,1);//wirkt wie zoom
neu = GetBlur1(vUv)/4;

  pq  = project (sxy, vec3 (q10,q11,q12));
  pq2 = project (sxz, vec3 (q10,q11,q12));
  mask1 = (pq.x>=0)* (pq.x <=width);
  mask2 = (pq2.x>=0)*(pq2.x <= depth);
  if (mask1) {neu = mix(neu,wall(pq),blend);}
  if (mask2) {neu = mix(neu,wall(pq2),blend);}

  pq  = project (-sxy, vec3 (q13,q14,q15));
  pq2 = project (sxz, vec3 (q13,q14,q15));
  mask1 = (pq.x>=0)* (pq.x <=width);
  mask2 = (pq2.x>=0)*(pq2.x <= depth);
  if (mask1) {neu = mix(neu,wall(pq),blend);}
  if (mask2) {neu = mix(neu,wall(pq2),blend);}

  pq  = project (sxy, vec3 (q16,q17,q18));
  pq2 = project (sxz, vec3 (q16,q17,q18));
  mask1 = (pq.x>=0)* (pq.x <=width) * (dist2 >=0);
  mask2 = (pq2.x>=0)*(pq2.x <= depth)* (dist2 >=0);
  if (mask1) {neu = wall(pq);}
  if (mask2) {neu = wall(pq2);}
  musr = (q29%2)/length(abs(fract(pq2/2)-.5))*mask2;
  musr += (q29%2)/length(abs(fract(pq/2)-.5))*mask1;

  pq  = project (-sxy, vec3 (q19,q20,q21));
  pq2 = project (sxz, vec3 (q19,q20,q21));
  mask1 = (pq.x>=0)* (pq.x <=width) * (dist2 <=0);
  mask2 = (pq2.x>=0)*(pq2.x <= depth)* (dist2 <=0);
  if (mask1) {neu = wall(pq);}
  if (mask2) {neu = wall(pq2);}
  musl = ((q29+1)%2)/length(abs(fract(pq2/2)-.5))*mask2;
  musl += ((q29+1)%2)/length(abs(fract(pq/2)-.5))*mask1;

ret = texture(sampler_main,vUv+neu/8)
+neu*(1+roam_cos)*clamp01(audioLowSmooth*.04/length(vUv-.5))/2
*(audioLowSmooth) + clamp01((musl*roam_sin+musr*roam_cos)/16)*audioMidSmooth;


  fragColor = ret;
}
